17	// Minimum buffer capacity.
18	const MIN_CAP: usize = 64;
19	// Maximum number of tasks that can be stolen in `steal_batch()` and `steal_batch_and_pop()`.
20	const MAX_BATCH: usize = 32;
21	// If a buffer of at least this size is retired, thread-local garbage is flushed so that it gets
22	// deallocated as soon as possible.
23	const FLUSH_THRESHOLD_BYTES: usize = 1 << 10;
24	
25	/// A buffer that holds tasks in a worker queue.
26	///
27	/// This is just a pointer to the buffer and its length - dropping an instance of this struct will
28	/// *not* deallocate the buffer.
29	struct Buffer<T> {
30	    /// Pointer to the allocated memory.
31	    ptr: *mut T,
32	
33	    /// Capacity of the buffer. Always a power of two.
34	    cap: usize,
35	}
36	
37	unsafe impl<T> Send for Buffer<T> {}
38	
39	impl<T> Buffer<T> {
40	    /// Allocates a new buffer with the specified capacity.
41	    fn alloc(cap: usize) -> Self {
42	        debug_assert_eq!(cap, cap.next_power_of_two());
43	
44	        let ptr = Box::into_raw(
45	            (0..cap)
46	                .map(|_| MaybeUninit::<T>::uninit())
47	                .collect::<Box<[_]>>(),
48	        )
49	        .cast::<T>();
50	
51	        Self { ptr, cap }
52	    }
53	
54	    /// Deallocates the buffer.
55	    unsafe fn dealloc(self) {
56	        drop(unsafe {
57	            Box::from_raw(ptr::slice_from_raw_parts_mut(
58	                self.ptr.cast::<MaybeUninit<T>>(),
59	                self.cap,
60	            ))
61	        });
62	    }
63	
64	    /// Returns a pointer to the task at the specified `index`.
65	    unsafe fn at(&self, index: isize) -> *mut T {
66	        // `self.cap` is always a power of two.
67	        // We do all the loads at `MaybeUninit` because we might realize, after loading, that we
68	        // don't actually have the right to access this memory.
69	        unsafe { self.ptr.offset(index & (self.cap - 1) as isize) }
70	    }
71	
72	    /// Writes `task` into the specified `index`.
73	    ///
74	    /// This method might be concurrently called with another `read` at the same index, which is
75	    /// technically speaking a data race and therefore UB. We should use an atomic store here, but
76	    /// that would be more expensive and difficult to implement generically for all types `T`.
77	    /// Hence, as a hack, we use a volatile write instead.
78	    unsafe fn write(&self, index: isize, task: MaybeUninit<T>) {
79	        unsafe { ptr::write_volatile(self.at(index).cast::<MaybeUninit<T>>(), task) }
80	    }
81	
82	    /// Reads a task from the specified `index`.
83	    ///
84	    /// This method might be concurrently called with another `write` at the same index, which is
85	    /// technically speaking a data race and therefore UB. We should use an atomic load here, but
86	    /// that would be more expensive and difficult to implement generically for all types `T`.
87	    /// Hence, as a hack, we use a volatile load instead.
88	    unsafe fn read(&self, index: isize) -> MaybeUninit<T> {
89	        unsafe { ptr::read_volatile(self.at(index).cast::<MaybeUninit<T>>()) }
90	    }
91	}
92	
93	impl<T> Clone for Buffer<T> {
94	    fn clone(&self) -> Self {
95	        *self
96	    }
97	}
98	
99	impl<T> Copy for Buffer<T> {}
