1313	/// An injector queue.
1314	///
1315	/// This is a FIFO queue that can be shared among multiple threads. Task schedulers typically have
1316	/// a single injector queue, which is the entry point for new tasks.
1317	///
1318	/// # Examples
1319	///
1320	/// ```
1321	/// # if option_env!("MIRI_FALLIBLE_WEAK_CAS").is_some() { return; } // see ci/miri.sh
1322	/// use crossbeam_deque::{Injector, Steal};
1323	///
1324	/// let q = Injector::new();
1325	/// q.push(1);
1326	/// q.push(2);
1327	///
1328	/// assert_eq!(q.steal(), Steal::Success(1));
1329	/// assert_eq!(q.steal(), Steal::Success(2));
1330	/// assert_eq!(q.steal(), Steal::Empty);
1331	/// ```
1332	pub struct Injector<T> {
1333	    /// The head of the queue.
1334	    head: CachePadded<Position<T>>,
1335	
1336	    /// The tail of the queue.
1337	    tail: CachePadded<Position<T>>,
1338	
1339	    /// Indicates that dropping a `Injector<T>` may drop values of type `T`.
1340	    _marker: PhantomData<T>,
1341	}
