1377	    /// Pushes a task into the queue.
1378	    ///
1379	    /// # Examples
1380	    ///
1381	    /// ```
1382	    /// use crossbeam_deque::Injector;
1383	    ///
1384	    /// let w = Injector::new();
1385	    /// w.push(1);
1386	    /// w.push(2);
1387	    /// ```
1388	    pub fn push(&self, task: T) {
1389	        let backoff = Backoff::new();
1390	        let mut tail = self.tail.index.load(Ordering::Acquire);
1391	        let mut block = self.tail.block.load(Ordering::Acquire);
1392	        let mut next_block = None;
1393	
1394	        loop {
1395	            // Calculate the offset of the index into the block.
1396	            let offset = (tail >> SHIFT) % LAP;
1397	
1398	            // If we reached the end of the block, wait until the next one is installed.
1399	            if offset == BLOCK_CAP {
1400	                backoff.snooze();
1401	                tail = self.tail.index.load(Ordering::Acquire);
1402	                block = self.tail.block.load(Ordering::Acquire);
1403	                continue;
1404	            }
1405	
1406	            // If we're going to have to install the next block, allocate it in advance in order to
1407	            // make the wait for other threads as short as possible.
1408	            if offset + 1 == BLOCK_CAP && next_block.is_none() {
1409	                next_block = Some(Block::<T>::new());
1410	            }
1411	
1412	            let new_tail = tail + (1 << SHIFT);
1413	
1414	            // Try advancing the tail forward.
1415	            match self.tail.index.compare_exchange_weak(
1416	                tail,
1417	                new_tail,
1418	                Ordering::SeqCst,
1419	                Ordering::Acquire,
1420	            ) {
1421	                Ok(_) => unsafe {
1422	                    // If we've reached the end of the block, install the next one.
1423	                    if offset + 1 == BLOCK_CAP {
1424	                        let next_block = Box::into_raw(next_block.unwrap());
1425	                        let next_index = new_tail.wrapping_add(1 << SHIFT);
1426	
1427	                        self.tail.block.store(next_block, Ordering::Release);
1428	                        self.tail.index.store(next_index, Ordering::Release);
1429	                        (*block).next.store(next_block, Ordering::Release);
1430	                    }
1431	
1432	                    // Write the task into the slot.
1433	                    let slot = (*block).slots.get_unchecked(offset);
1434	                    slot.task.get().write(MaybeUninit::new(task));
1435	                    slot.state.fetch_or(WRITE, Ordering::Release);
1436	
1437	                    return;
1438	                },
1439	                Err(t) => {
1440	                    tail = t;
1441	                    block = self.tail.block.load(Ordering::Acquire);
1442	                    backoff.spin();
1443	                }
1444	            }
1445	        }
1446	    }
