1448	    /// Steals a task from the queue.
1449	    ///
1450	    /// # Examples
1451	    ///
1452	    /// ```
1453	    /// # if option_env!("MIRI_FALLIBLE_WEAK_CAS").is_some() { return; } // see ci/miri.sh
1454	    /// use crossbeam_deque::{Injector, Steal};
1455	    ///
1456	    /// let q = Injector::new();
1457	    /// q.push(1);
1458	    /// q.push(2);
1459	    ///
1460	    /// assert_eq!(q.steal(), Steal::Success(1));
1461	    /// assert_eq!(q.steal(), Steal::Success(2));
1462	    /// assert_eq!(q.steal(), Steal::Empty);
1463	    /// ```
1464	    pub fn steal(&self) -> Steal<T> {
1465	        let mut head;
1466	        let mut block;
1467	        let mut offset;
1468	
1469	        let backoff = Backoff::new();
1470	        loop {
1471	            head = self.head.index.load(Ordering::Acquire);
1472	            block = self.head.block.load(Ordering::Acquire);
1473	
1474	            // Calculate the offset of the index into the block.
1475	            offset = (head >> SHIFT) % LAP;
1476	
1477	            // If we reached the end of the block, wait until the next one is installed.
1478	            if offset == BLOCK_CAP {
1479	                backoff.snooze();
1480	            } else {
1481	                break;
1482	            }
1483	        }
1484	
1485	        let mut new_head = head + (1 << SHIFT);
1486	
1487	        if new_head & HAS_NEXT == 0 {
1488	            atomic::fence(Ordering::SeqCst);
1489	            let tail = self.tail.index.load(Ordering::Relaxed);
1490	
1491	            // If the tail equals the head, that means the queue is empty.
1492	            if head >> SHIFT == tail >> SHIFT {
1493	                return Steal::Empty;
1494	            }
1495	
1496	            // If head and tail are not in the same block, set `HAS_NEXT` in head.
1497	            if (head >> SHIFT) / LAP != (tail >> SHIFT) / LAP {
1498	                new_head |= HAS_NEXT;
1499	            }
1500	        }
1501	
1502	        // Try moving the head index forward.
1503	        if self
1504	            .head
1505	            .index
1506	            .compare_exchange_weak(head, new_head, Ordering::SeqCst, Ordering::Acquire)
1507	            .is_err()
1508	        {
1509	            return Steal::Retry;
1510	        }
1511	
1512	        unsafe {
1513	            // If we've reached the end of the block, move to the next one.
1514	            if offset + 1 == BLOCK_CAP {
1515	                let next = (*block).wait_next();
1516	                let mut next_index = (new_head & !HAS_NEXT).wrapping_add(1 << SHIFT);
1517	                if !(*next).next.load(Ordering::Relaxed).is_null() {
1518	                    next_index |= HAS_NEXT;
1519	                }
1520	
1521	                self.head.block.store(next, Ordering::Release);
1522	                self.head.index.store(next_index, Ordering::Release);
1523	            }
1524	
1525	            // Read the task.
1526	            let slot = (*block).slots.get_unchecked(offset);
1527	            slot.wait_write();
1528	            let task = slot.task.get().read().assume_init();
1529	
1530	            // Destroy the block if we've reached the end, or if another thread wanted to destroy
1531	            // but couldn't because we were busy reading from the slot.
1532	            if (offset + 1 == BLOCK_CAP)
1533	                || (slot.state.fetch_or(READ, Ordering::AcqRel) & DESTROY != 0)
1534	            {
1535	                Block::destroy(block, offset);
1536	            }
1537	
1538	            Steal::Success(task)
1539	        }
1540	    }
