1542	    /// Steals a batch of tasks and pushes them into a worker.
1543	    ///
1544	    /// How many tasks exactly will be stolen is not specified. That said, this method will try to
1545	    /// steal around half of the tasks in the queue, but also not more than some constant limit.
1546	    ///
1547	    /// # Examples
1548	    ///
1549	    /// ```
1550	    /// # if option_env!("MIRI_FALLIBLE_WEAK_CAS").is_some() { return; } // see ci/miri.sh
1551	    /// use crossbeam_deque::{Injector, Worker};
1552	    ///
1553	    /// let q = Injector::new();
1554	    /// q.push(1);
1555	    /// q.push(2);
1556	    /// q.push(3);
1557	    /// q.push(4);
1558	    ///
1559	    /// let w = Worker::new_fifo();
1560	    /// let _ = q.steal_batch(&w);
